package com.example.grpc.interceptor;

import io.grpc.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.UUID;

/**
 * Server interceptor that catches any unhandled exceptions and ensures
 * they never leak internal details to the client.
 * 
 * This acts as a safety net in case individual service methods miss
 * an exception path.
 */
public class SecureGrpcInterceptor implements ServerInterceptor {

    private static final Logger logger = LoggerFactory.getLogger(SecureGrpcInterceptor.class);

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        // Wrap the server call to intercept close/error
        ServerCall<ReqT, RespT> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
            @Override
            public void close(io.grpc.Status status, Metadata trailers) {
                if (status.getCode() != io.grpc.Status.Code.OK) {
                    String correlationId = UUID.randomUUID().toString();

                    // Log the full error server-side
                    if (status.getCause() != null) {
                        logger.error("gRPC call failed [correlationId={}, method={}, code={}]: {}",
                                correlationId,
                                call.getMethodDescriptor().getFullMethodName(),
                                status.getCode(),
                                status.getCause().getMessage(),
                                status.getCause());
                    } else {
                        logger.error("gRPC call failed [correlationId={}, method={}, code={}]: {}",
                                correlationId,
                                call.getMethodDescriptor().getFullMethodName(),
                                status.getCode(),
                                status.getDescription());
                    }

                    // Sanitize the status before sending to client
                    io.grpc.Status sanitizedStatus = sanitizeStatus(status, correlationId);
                    Metadata sanitizedTrailers = sanitizeMetadata(trailers, correlationId);
                    super.close(sanitizedStatus, sanitizedTrailers);
                    return;
                }
                super.close(status, trailers);
            }
        };

        // Wrap the listener to catch exceptions during message processing
        ServerCall.Listener<ReqT> listener;
        try {
            listener = next.startCall(wrappedCall, headers);
        } catch (Exception e) {
            String correlationId = UUID.randomUUID().toString();
            logger.error("Exception starting gRPC call [correlationId={}]: {}", correlationId, e.getMessage(), e);
            call.close(
                    io.grpc.Status.INTERNAL.withDescription(
                            "Internal error. Reference: " + correlationId),
                    new Metadata());
            return new ServerCall.Listener<ReqT>() {};
        }

        return new ForwardingServerCallListener.SimpleForwardingServerCallListener<ReqT>(listener) {
            @Override
            public void onMessage(ReqT message) {
                try {
                    super.onMessage(message);
                } catch (Exception e) {
                    String correlationId = UUID.randomUUID().toString();
                    logger.error("Exception processing message [correlationId={}]: {}", correlationId, e.getMessage(), e);
                    call.close(
                            io.grpc.Status.INTERNAL.withDescription(
                                    "Internal error. Reference: " + correlationId),
                            new Metadata());
                }
            }

            @Override
            public void onHalfClose() {
                try {
                    super.onHalfClose();
                } catch (Exception e) {
                    String correlationId = UUID.randomUUID().toString();
                    logger.error("Exception in onHalfClose [correlationId={}]: {}", correlationId, e.getMessage(), e);
                    call.close(
                            io.grpc.Status.INTERNAL.withDescription(
                                    "Internal error. Reference: " + correlationId),
                            new Metadata());
                }
            }
        };
    }

    /**
     * Strips internal details from the gRPC status.
     * Removes the cause (which may contain stack traces) and replaces
     * the description with a safe, generic message.
     */
    private io.grpc.Status sanitizeStatus(io.grpc.Status status, String correlationId) {
        switch (status.getCode()) {
            case INVALID_ARGUMENT:
            case NOT_FOUND:
            case ALREADY_EXISTS:
            case PERMISSION_DENIED:
            case UNAUTHENTICATED:
            case FAILED_PRECONDITION:
            case OUT_OF_RANGE:
                // For client-facing error codes, we can keep a sanitized description
                // but still strip the cause
                String safeDescription = status.getDescription();
                if (safeDescription != null && safeDescription.length() > 200) {
                    safeDescription = safeDescription.substring(0, 200);
                }
                return status.getCode().toStatus()
                        .withDescription(safeDescription != null ? safeDescription :
                                "Request error. Reference: " + correlationId);

            case INTERNAL:
            case UNKNOWN:
            case DATA_LOSS:
            case UNAVAILABLE:
            case DEADLINE_EXCEEDED:
            case RESOURCE_EXHAUSTED:
            case ABORTED:
            case UNIMPLEMENTED:
            case CANCELLED:
            default:
                // For server-side error codes, always use a generic message
                return status.getCode().toStatus()
                        .withDescription("An error occurred. Reference: " + correlationId);
        }
    }

    /**
     * Removes any potentially sensitive metadata keys from trailers.
     */
    private Metadata sanitizeMetadata(Metadata trailers, String correlationId) {
        Metadata sanitized = new Metadata();
        // Only copy known-safe keys; drop everything else
        Metadata.Key<String> correlationKey =
                Metadata.Key.of("x-correlation-id", Metadata.ASCII_STRING_MARSHALLER);
        sanitized.put(correlationKey, correlationId);
        return sanitized;
    }
}


