package com.example.grpc.server;

import com.example.grpc.interceptor.SecureGrpcInterceptor;
import com.example.grpc.service.SecureGrpcService;
import io.grpc.Server;
import io.grpc.ServerBuilder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.File;
import java.io.IOException;

public class GrpcServer {

    private static final Logger logger = LoggerFactory.getLogger(GrpcServer.class);
    private static final int PORT = 9090;

    private Server server;

    public void start() throws IOException {
        server = ServerBuilder.forPort(PORT)
                // Register the global security interceptor first
                .intercept(new SecureGrpcInterceptor())
                // Register service implementations
                .addService(new SecureGrpcService())
                // Use TLS in production
                // .useTransportSecurity(new File("cert.pem"), new File("key.pem"))
                .build()
                .start();

        logger.info("gRPC server started on port {}", PORT);

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            logger.info("Shutting down gRPC server...");
            GrpcServer.this.stop();
            logger.info("gRPC server shut down.");
        }));
    }

    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        GrpcServer grpcServer = new GrpcServer();
        grpcServer.start();
        grpcServer.blockUntilShutdown();
    }
}


